using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // [EF9 Breaking] HasIndex throws at startup for Cosmos — removed.
        // Manage indexing policy via Azure Portal, Bicep, or Terraform.

        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // [EF9 Breaking] Default discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
            // Preserve the old property name so existing documents and SQL queries remain compatible.
            entity.HasDiscriminator<string>("Discriminator");

            // [EF9 Breaking] id values no longer include the discriminator prefix.
            // EF Core 8 wrote ids as "Product|123"; EF Core 9 writes just "123".
            // Existing documents still have the compound format — without this flag,
            // FindAsync and point-reads would generate the wrong id and miss every document.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

