using System.Linq;
using System.Threading.Tasks;

class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator (preserved via HasDiscriminator config).
        // If you had used the EF9 default "$type", this query would silently return zero results.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // [EF9 Breaking] Sync I/O (ToList, SaveChanges, etc.) now throws on the Cosmos provider.
        // Use async equivalents: ToListAsync, SaveChangesAsync, FirstOrDefaultAsync, etc.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

